 1→import { Box, Group, Stack, Text } from '@mantine/core'
 2→import { MapPin, DollarSign } from 'lucide-react'
 3→import type { SearchInstitution } from './types'
 4→
 5→function formatDistance(d: number): string {
 6→  if (d < 1) return '< 1 mi'
 7→  return `${Math.round(d)} mi`
 8→}
 9→
10→function formatPrice(p: number): string {
11→  return `$${p.toLocaleString()}`
12→}
13→
14→interface ResultsListProps {
15→  institutions: SearchInstitution[]
16→  hasLocation: boolean
17→  hasState: boolean
18→  onClickInstitution: (unitID: string) => void
19→}
20→
21→export function ResultsList({
22→  institutions,
23→  hasLocation,
24→  hasState,
25→  onClickInstitution,
26→}: ResultsListProps) {
27→  return (
28→    <Stack gap={0}>
29→      {institutions.map((inst) => (
30→        <Box
31→          key={inst.unitID}
32→          role="button"
33→          tabIndex={0}
34→          onClick={() => onClickInstitution(inst.unitID)}
35→          onKeyDown={(e) => {
36→            if (e.key === 'Enter' || e.key === ' ') {
37→              e.preventDefault()
38→              onClickInstitution(inst.unitID)
39→            }
40→          }}
41→          style={{
42→            cursor: 'pointer',
43→            padding: '8px 12px',
44→            borderBottom: '1px solid var(--mantine-color-gray-2)',
45→          }}
46→        >
47→          <Group justify="space-between" wrap="nowrap" gap="sm">
48→            <Group gap="xs" wrap="nowrap" style={{ minWidth: 0 }}>
49→              <Text fw={600} c="brand.9" truncate="end" style={{ minWidth: 0 }}>
50→                {inst.name}
51→              </Text>
52→              <Text fz="sm" c="dimmed" style={{ whiteSpace: 'nowrap' }}>
53→                {inst.city}, {inst.state}
54→              </Text>
55→            </Group>
56→            {(hasLocation || hasState) && (
57→              <Group gap="sm" wrap="nowrap" style={{ flexShrink: 0 }}>
58→                {hasLocation && inst.distance != null && (
59→                  <Text
60→                    fz="sm"
61→                    c="dimmed"
62→                    data-testid="distance"
63→                    style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}
64→                  >
65→                    <MapPin size={14} />
66→                    {formatDistance(inst.distance)}
67→                  </Text>
68→                )}
69→                {hasState && inst.myPrice != null && (
70→                  <Text
71→                    fz="sm"
72→                    c="dimmed"
73→                    data-testid="my-price"
74→                    style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}
75→                  >
76→                    <DollarSign size={14} />
77→                    {formatPrice(inst.myPrice)}
78→                  </Text>
79→                )}
80→              </Group>
81→            )}
82→          </Group>
83→        </Box>
84→      ))}
85→    </Stack>
86→  )
87→}
88→
